const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

const authHeader = $('Receive Ingest Request').first().json.headers.authorization ?? '';
const token = authHeader.replace('Bearer ', '').trim();

return [{ json: { hmac_valid: true, token } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

if (!session.user_active) {
  throw new Error('User account is inactive');
}

if (!session.client_active) {
  throw new Error('Client account is inactive');
}

if (session.is_caiac_staff !== true) {
  throw new Error('Insufficient permissions: is_caiac_staff required');
}

const clientUUID = $('Get Webhook Secret').first().json.id;
const body = $('Receive Ingest Request').first().json.body;

return [{
  json: {
    user_id: session.user_id,
    is_caiac_staff: true,
    client_id: clientUUID,
    client_slug: body.client_id,
    filename: body.filename,
    role: body.role,
    file_b64: body.file_b64
  }
}];

const session = $('Receive Ingest Request').item.json.body;
const file_b64 = session.file_base64;
const fileSizeBytes = Math.round(file_b64.length * 0.75);
const estimatedPages = Math.round(fileSizeBytes / 75000);
const fileSizeMB = (fileSizeBytes / 1048576).toFixed(1);
if (estimatedPages > 100) {
  throw new Error(`"${session.filename}" is ~${estimatedPages} pages (${fileSizeMB} MB) — exceeds the 100-page CPX31 limit.`);
}
return [{ json: { ...session, estimated_pages: estimatedPages } }];

const doclingResult = $input.first().json;
const session = $('Check Token Valid').first().json;

const rawChunks = doclingResult.chunks || [];
if (!rawChunks.length) {
  throw new Error('Docling returned no chunks for ' + (session.filename || 'unknown'));
}

return rawChunks
  .map((c, i) => {
    const text = typeof c === 'string' ? c : (c.text || c.content || '');
    if (!text.trim()) return null;
    return { json: {
      text,
      chunk_index: i,
      chunk_count: rawChunks.length,
      filename: session.filename,
      client_id: session.client_id,
      client_slug: session.client_slug,
      role: session.role,
      user_id: session.user_id,
    }};
  })
  .filter(Boolean);

const embeddingItems = $input.all();
const chunkItems = $('Embed and Prepare Points').all();

if (embeddingItems.length !== chunkItems.length) {
  throw new Error(`Embedding count mismatch`);
}

const points = embeddingItems.map((item, i) => {
  const embedding = item.json.embedding;
  if (!embedding || !embedding.length) throw new Error('Empty embedding for chunk ' + i);
  const chunk = chunkItems[i].json;
  const pointId = Math.abs((Date.now() + i * 997) % 2147483647);
  return {
    id: pointId,
    vector: embedding,
    payload: { text: chunk.text, source: chunk.filename, client_id: chunk.client_slug, type: 'document', role: chunk.role, chunk_index: chunk.chunk_index }
  };
});

const meta = chunkItems[0].json;
return [{ json: { points, count: points.length, client_slug: meta.client_slug, client_id: meta.client_id, filename: meta.filename, role: meta.role, user_id: meta.user_id } }];
